ROOT := ..
BUILD := build

RV_CC_CANDIDATES := riscv64-linux-gnu-gcc riscv64-linux-gcc riscv64-linux-musl-gcc riscv64-unknown-elf-gcc riscv64-buildroot-linux-musl-gcc
LA_CC_CANDIDATES := loongarch64-linux-gnu-gcc loongarch64-linux-musl-gcc loongarch64-unknown-linux-gnu-gcc

RV_CC ?= $(firstword $(foreach c,$(RV_CC_CANDIDATES),$(shell command -v $(c) 2>/dev/null)))
LA_CC ?= $(firstword $(foreach c,$(LA_CC_CANDIDATES),$(shell command -v $(c) 2>/dev/null)))

COMMON_C := common/main.c common/print.c common/string.c common/virtio.c fs/ext4.c \
	fs/fd.c syscall/linux_compat.c proc/user.c

CFLAGS := -std=gnu11 -O2 -g0 -ffreestanding -fno-common -fno-builtin \
	-fno-stack-protector -fno-pic -fno-pie -nostdlib -Wall -Wextra \
	-Iinclude
LDFLAGS := -nostdlib -static -Wl,--gc-sections

.PHONY: all rv la toolchain clean

all: rv la

toolchain:
	@echo "RV_CC=$(RV_CC)"
	@echo "LA_CC=$(LA_CC)"
	@test -n "$(RV_CC)" || { echo "No RISC-V gcc found in: $(RV_CC_CANDIDATES)"; exit 127; }
	@test -n "$(LA_CC)" || { echo "No LoongArch gcc found in: $(LA_CC_CANDIDATES)"; exit 127; }

rv: $(ROOT)/kernel-rv
la: $(ROOT)/kernel-la

$(ROOT)/kernel-rv: arch/riscv64/entry.S arch/riscv64/trap.S arch/riscv64/arch.c arch/riscv64/linker.ld $(COMMON_C)
	@test -n "$(RV_CC)" || { echo "No RISC-V gcc found. Install/provide RV_CC=..."; exit 127; }
	@mkdir -p $(BUILD)/riscv64
	$(RV_CC) $(CFLAGS) -DARCH_RISCV64 -march=rv64gc -mabi=lp64d -mcmodel=medany -msmall-data-limit=0 \
		-T arch/riscv64/linker.ld $(LDFLAGS) \
		arch/riscv64/entry.S arch/riscv64/trap.S arch/riscv64/arch.c $(COMMON_C) -o $@

$(ROOT)/kernel-la: arch/loongarch64/entry.S arch/loongarch64/arch.c arch/loongarch64/linker.ld $(COMMON_C)
	@test -n "$(LA_CC)" || { echo "No LoongArch gcc found. Install/provide LA_CC=..."; exit 127; }
	@mkdir -p $(BUILD)/loongarch64
	$(LA_CC) $(CFLAGS) -DARCH_LOONGARCH64 -march=loongarch64 -mabi=lp64d -mcmodel=large \
		-T arch/loongarch64/linker.ld $(LDFLAGS) \
		arch/loongarch64/entry.S arch/loongarch64/arch.c $(COMMON_C) -o $@

clean:
	rm -rf $(BUILD)

