static int str_eq(const char *a, const char *b) {
    size_t i = 0;
    while (a[i] && b[i] && a[i] == b[i]) {
        i++;
    }
    return a[i] == b[i];
}

static void make_lib_path(char *dst, size_t cap, const char *lib_dir, const char *name) {
    size_t p = 0;
    if (cap == 0) {
        return;
    }
    dst[p++] = '/';
    for (size_t i = 0; lib_dir[i] && p + 1 < cap; i++) {
        dst[p++] = lib_dir[i];
    }
    if (lib_dir[0] && p + 1 < cap) {
        dst[p++] = '/';
    }
    for (size_t i = 0; name[i] && p + 1 < cap; i++) {
        dst[p++] = name[i];
    }
    dst[p] = '\0';
}

static int ext4_file_exists(const char *path) {
    uint32_t ino = 0;
    uint32_t size = 0;
    uint8_t typ = 0;
    return ext4_lookup_path(path, 2, &ino, &size, &typ) == 0 && typ == 1;
}

static int ext4_dir_exists(const char *path) {
    uint32_t ino = 0;
    uint32_t size = 0;
    uint8_t typ = 0;
    return ext4_lookup_path(path, 2, &ino, &size, &typ) == 0 && typ == 2;
}

