static inline uint32_t mmio_read(uint32_t off) {
    return *(volatile uint32_t *)(uintptr_t)(VIRTIO_BASE + off);
}

static inline void mmio_write(uint32_t off, uint32_t value) {
    *(volatile uint32_t *)(uintptr_t)(VIRTIO_BASE + off) = value;
}

static inline void fence_io(void) {
#if defined(__riscv)
    asm volatile ("fence iorw, iorw" ::: "memory");
#else
    __sync_synchronize();
#endif
}

static uint64_t virtio_dma_addr(const void *ptr) {
